PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?club ?clubLabel(COUNT(DISTINCT ?final) AS ?count) WHERE {
  VALUES ?club {
    wd:Q3044572 wd:Q858633 wd:Q911681 wd:Q251090 wd:Q249679
  }
  {
    ?final wdt:P1346 ?club
  } UNION {
    ?final wdt:P1454 ?club
  }
  OPTIONAL {
    ?club rdfs:label ?clubLabel
    FILTER(LANG(?clubLabel) = "en")
  }
}
GROUP BY ?club ?clubLabel
ORDER BY ASC(?count)
